commands.effect_on_receipt:
tempOptions := Options
for each bit i:
  if OptionsMask[i] == 1:
    tempOptions[i] := OptionsOverride[i]
  else:
    tempOptions[i] := Options[i]
process_Options(tempOptions)
// perform level transition
if TransitionTime != null:
  duration := TransitionTime * 0.1s
else if OnOffTransitionTime is present:
  duration := OnOffTransitionTime * 0.1s
else:
  duration := MIN_PRACTICAL_TIME
if device_supports_variable_rate == false:
  // MAY ignore duration
  duration := MIN_PRACTICAL_TIME
move_level_continuous(from=CurrentLevel, to=Level, over=duration)

if Rate == 0:
  send_default_response(status=INVALID_COMMAND)
  return
// build and process temp options as MoveToLevel
tempOptions := Options
for each bit i:
  if OptionsMask[i] == 1:
    tempOptions[i] := OptionsOverride[i]
  else:
    tempOptions[i] := Options[i]
process_Options(tempOptions)
// determine effective rate
if Rate != null:
  effRate := Rate
else if DefaultMoveRate is supported and DefaultMoveRate != null:
  effRate := DefaultMoveRate
else:
  effRate := MAX_PRACTICAL_RATE
if device_supports_variable_rate == false:
  effRate := MAX_PRACTICAL_RATE
if MoveMode == Up:
  move_level_continuous(from=CurrentLevel, to=DeviceMaxLevel, rate=effRate, stop_at_limit=true)
else if MoveMode == Down:
  move_level_continuous(from=CurrentLevel, to=DeviceMinLevel, rate=effRate, stop_at_limit=true)

if StepSize == 0:
  send_default_response(status=INVALID_COMMAND)
  return
// build and process temp options as MoveToLevel
tempOptions := Options
for each bit i:
  if OptionsMask[i] == 1:
    tempOptions[i] := OptionsOverride[i]
  else:
    tempOptions[i] := Options[i]
process_Options(tempOptions)
// compute target level
delta := StepSize
if StepMode == Up:
  target := min(CurrentLevel + delta, DeviceMaxLevel)
else if StepMode == Down:
  target := max(CurrentLevel - delta, DeviceMinLevel)
// compute duration
if TransitionTime != null:
  baseDuration := TransitionTime * 0.1s
else:
  baseDuration := MIN_PRACTICAL_TIME
// if clamped before full step, scale duration
actualDelta := abs(target - CurrentLevel)
if actualDelta < StepSize and StepSize > 0:
  duration := baseDuration * actualDelta / StepSize
else:
  duration := baseDuration
if device_supports_variable_rate == false:
  duration := MIN_PRACTICAL_TIME
move_level_continuous(from=CurrentLevel, to=target, over=duration)

// build and process temp options as MoveToLevel
tempOptions := Options
for each bit i:
  if OptionsMask[i] == 1:
    tempOptions[i] := OptionsOverride[i]
  else:
    tempOptions[i] := Options[i]
process_Options(tempOptions)
// stop any level movement
if command_in_progress in {MoveToLevel, Move, Step, MoveToLevelWithOnOff, MoveWithOnOff, StepWithOnOff}:
  terminate_level_transition()
CurrentLevel := CurrentLevel  // leave as value at receipt time
RemainingTime := 0

// perform MoveToLevel behavior
call MoveToLevel_effect(this_payload)
// On/Off linkage
if implemented(OnOffCluster):
  if resulting_CurrentLevel > DeviceMinLevel:
    OnOffCluster.OnOff := TRUE
  if resulting_CurrentLevel == DeviceMinLevel:
    OnOffCluster.OnOff := FALSE

// perform Move behavior
call Move_effect(this_payload)
// During movement, ensure OnOff matches level
if implemented(OnOffCluster):
  if command_effect_sets_CurrentLevel_above_min():
    OnOffCluster.OnOff := TRUE
  if command_effect_sets_CurrentLevel_to_min():
    OnOffCluster.OnOff := FALSE

// perform Step behavior
call Step_effect(this_payload)
// On/Off linkage for resulting level
if implemented(OnOffCluster):
  if resulting_CurrentLevel > DeviceMinLevel:
    OnOffCluster.OnOff := TRUE
  if resulting_CurrentLevel == DeviceMinLevel:
    OnOffCluster.OnOff := FALSE

// identical to Stop
call Stop_effect(this_payload)
// On/Off behavior is determined by the original command that was stopped; no extra handling here.
